import { readFile } from "fs";
import { basename, join } from "path";
import { glob } from "glob";
import { promisify } from "util";
import { BASE_URL } from "@/utils/common";

export type Theme = {
  author: string;
  authorUsername: string;
  version: string;
  name: string;
  slug?: string;
  appearance: "light" | "dark";
  colors: {
    background: string;
    backgroundSecondary: string;
    text: string;
    selection: string;
    loader: string;
    red: string;
    orange: string;
    yellow: string;
    green: string;
    blue: string;
    purple: string;
    magenta: string;
  };
};

const themesDir = join(process.cwd(), "app", "(navigation)", "themes", "themes");

const readFileAsync = promisify(readFile);

export async function getAllThemes(): Promise<Theme[]> {
  const allThemePaths = await glob(`${themesDir}/**/*.json`);
  const sortedThemePaths = allThemePaths.sort((a, b) => {
    const aFileName = basename(a);
    const bFileName = basename(b);
    return aFileName.localeCompare(bFileName);
  });

  const themes = await Promise.all(
    sortedThemePaths.map(async (filePath) => {
      const fileName = basename(filePath);
      const data = await readFileAsync(filePath);
      const themeData = JSON.parse(data.toString());

      const parentDirName = basename(filePath.replace(fileName, ""));
      const slug = `${parentDirName}/${fileName.replace(".json", "")}`.toLowerCase();

      return {
        ...themeData,
        slug,
        og_image: `${BASE_URL}/themes/${slug}/opengraph-image`,
      };
    }),
  );

  return themes;
}

// This function checks whether the query params generated from Raycast's Theme Studio
// can be converted into a Theme object that is used in this App
function canConvertParamsToTheme(params: any): boolean {
  const { appearance, name, version, colors } = params;
  return appearance && name && version && colors;
}

function convertLegacyColorIfNeeded(color: string) {
  const [hex, value] = color.split("#");
  if (value.length === 8) {
    return `#${value.slice(0, -2)}`;
  }
  return color;
}

// This function converts the query params generated from Raycast's Theme Studio
// into a Theme object that is used in this App
export function makeThemeObjectFromParams(params: any): Theme | undefined {
  if (canConvertParamsToTheme(params)) {
    const { appearance, name, author, authorUsername, version, colors: colorString } = params;

    const colorArray = colorString.split(",");

    const colorObject = {
      background: convertLegacyColorIfNeeded(colorArray[0]),
      backgroundSecondary: convertLegacyColorIfNeeded(colorArray[1]),
      text: convertLegacyColorIfNeeded(colorArray[2]),
      selection: convertLegacyColorIfNeeded(colorArray[3]),
      loader: convertLegacyColorIfNeeded(colorArray[4]),
      red: convertLegacyColorIfNeeded(colorArray[5]),
      orange: convertLegacyColorIfNeeded(colorArray[6]),
      yellow: convertLegacyColorIfNeeded(colorArray[7]),
      green: convertLegacyColorIfNeeded(colorArray[8]),
      blue: convertLegacyColorIfNeeded(colorArray[9]),
      purple: convertLegacyColorIfNeeded(colorArray[10]),
      magenta: convertLegacyColorIfNeeded(colorArray[11]),
    };

    return {
      appearance,
      name,
      version,
      author,
      authorUsername,
      colors: colorObject,
    };
  } else {
    return undefined;
  }
}

"use client";
import { Theme } from "@themes/lib/theme";
import React from "react";

type RaycastThemeContextType = {
  activeTheme: Theme | undefined;
  setActiveTheme: (theme: Theme) => void;
};

export const RaycastThemeContext = React.createContext<RaycastThemeContextType>({
  activeTheme: undefined,
  setActiveTheme: () => {},
});

export function RaycastThemeProvider({ children }: { children: React.ReactNode }) {
  const [activeTheme, setActiveTheme] = React.useState<Theme | undefined>(undefined);

  const handleSetActiveTheme = (theme: Theme) => {
    setActiveTheme(theme);
  };

  const handleTitleChange = (title: string) => {
    return (document.title = title);
  };

  const handleURLChange = (slug: string) => {
    const searchParams = new URLSearchParams(window.location.search);

    window.history.replaceState({}, "", `/themes/${slug}${searchParams.size > 0 ? `?${searchParams.toString()}` : ""}`);
  };

  React.useEffect(() => {
    if (activeTheme) {
      document.documentElement.classList.remove("light", "dark");
      document.documentElement.classList.add(activeTheme.appearance);
      document.documentElement.style.colorScheme = activeTheme.appearance;
      if (activeTheme.slug) {
        handleURLChange(activeTheme.slug);
      }
      handleTitleChange(`${activeTheme.name} by ${activeTheme.author}`);
    }
  }, [activeTheme]);

  return (
    <RaycastThemeContext.Provider
      value={{
        activeTheme,
        setActiveTheme: handleSetActiveTheme,
      }}
    >

"use client";
import { List } from "@themes/components/raycast/list";
import { Grid } from "@themes/components/raycast/grid";
import { RootFooter } from "@themes/components/raycast/root-footer";
import { RootHeader } from "@themes/components/raycast/root-header";
import { useRaycastTheme } from "@themes/components/raycast-theme-provider";
import { Theme } from "@themes/lib/theme";
import { alpha } from "@themes/lib/alpha";

export function Raycast({
  theme: forcedTheme,
  disableLoadingAnimation,
  thumbnail,
}: {
  theme?: Theme;
  disableLoadingAnimation?: boolean;
  thumbnail?: boolean;
}) {
  const { activeTheme } = useRaycastTheme();

  const theme = forcedTheme || activeTheme;

  const style = {
    "--backgroundPrimary": `${theme?.colors.background}${alpha["40"]}`,
    "--backgroundSecondary": theme?.colors.backgroundSecondary
      ? `${theme?.colors.backgroundSecondary}${alpha["40"]}`
      : `${theme?.colors.background}${alpha["40"]}`,
    "--border-100": `${theme?.colors.text}${alpha["10"]}`,
    "--border-200": `${theme?.colors.text}${alpha["20"]}`,
    "--text": `${theme?.colors.text}`,
    "--text-100": `${theme?.colors.text}${alpha["10"]}`,
    "--text-400": `${theme?.colors.text}${alpha["40"]}`,
    "--text-600": `${theme?.colors.text}${alpha["60"]}`,
    "--loader": `${theme?.colors.loader}`,
    "--selection": `${theme?.colors.selection}`,
    "--selection-100": `${theme?.colors.selection}${alpha["10"]}`,
    "--green": `${theme?.colors.green}`,
    "--green-100": `${theme?.colors.green}${alpha["15"]}`,
    "--yellow": `${theme?.colors.yellow}`,
    "--yellow-100": `${theme?.colors.yellow}${alpha["15"]}`,
    "--red": `${theme?.colors.red}`,
    "--red-100": `${theme?.colors.red}${alpha["15"]}`,
    "--orange": `${theme?.colors.orange}`,
    "--orange-100": `${theme?.colors.orange}${alpha["15"]}`,
    "--blue": `${theme?.colors.blue}`,
    "--blue-100": `${theme?.colors.blue}${alpha["15"]}`,
    "--purple": `${theme?.colors.purple}`,
    "--purple-100": `${theme?.colors.purple}${alpha["15"]}`,
    "--magenta": `${theme?.colors.magenta}`,
    "--magenta-100": `${theme?.colors.magenta}${alpha["15"]}`,
  };

  return (
    <div
      data-raycast
      className={`w-[750px] h-[475px] rounded-[18px] shadow flex flex-col relative select-none shrink-0 text-left overflow-hidden ${
        !thumbnail ? "backdrop-blur-[72px]" : ""
      }`}
      style={{
        ...style,
        zIndex: 2,

        backgroundColor: activeTheme?.appearance === "dark" ? "rgba(128, 128, 128, 0.2)" : "rgba(255, 255, 255, 0.2)",

        backgroundImage: `linear-gradient(to bottom, var(--backgroundPrimary) 0%, var(--backgroundSecondary) 70%)`,
        boxShadow: `inset 0 0 0 1px var(--border-200)`,
      }}
    >
      <RootHeader
        disableLoadingAnimation={disableLoadingAnimation}
        loadingAnimationType={thumbnail ? "static" : "animated"}
      />

      <div className="flex-1 overflow-hidden py-1">
        <List />
        {activeTheme && <Grid mode={activeTheme.appearance} />}
      </div>

      <RootFooter mode={theme?.appearance} />
    </div>
  );
}

export function RootHeader({
